Here's a complete example:

**XAML (ItemsPage.xaml)**
```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.ItemsPage">

    <RefreshView Command="{Binding RefreshCommand}"
                 IsRefreshing="{Binding IsRefreshing}">

        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding SelectedItem}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">
            <CollectionView.ItemTemplate>
                <DataTemplate>
                    <Grid Padding="10" ColumnDefinitions="*,Auto">
                        <Label Text="{Binding Name}" FontSize="16" />
                        <Label Grid.Column="1" Text="{Binding Status}"
                               TextColor="Gray" />
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
        </CollectionView>

    </RefreshView>
</ContentPage>
```

**ViewModel (ItemsViewModel.cs)**
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> _items = new();

    [ObservableProperty]
    private bool _isRefreshing;

    [ObservableProperty]
    private Item? _selectedItem;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        var data = await _api.GetItemsAsync();
        Items = new ObservableCollection<Item>(data);
        IsRefreshing = false;           // stops the spinner
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (SelectedItem is null) return;

        await _nav.GoToAsync(
            nameof(DetailPage),
            new Dictionary<string, object> { ["Item"] = SelectedItem });

        SelectedItem = null;            // clear so re-selection works
    }
}
```

**Key binding relationships:**

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `RefreshView.Command` | `RefreshCommand` | Triggers API reload on pull |
| `RefreshView.IsRefreshing` | `IsRefreshing` | Controls spinner; set `false` when done |
| `CollectionView.ItemsSource` | `Items` | The data collection |
| `CollectionView.SelectedItem` | `SelectedItem` | Two-way; tracks current selection |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires navigation, then nulls `SelectedItem` |

**Important details:**
- Setting `SelectedItem = null` after navigation lets the user tap the same item again later.
- `IsRefreshing = false` must be set explicitly — the `RefreshView` won't stop spinning on its own.
- Uses **CommunityToolkit.Mvvm** source generators (`[ObservableProperty]`, `[RelayCommand]`) to eliminate boilerplate.
